Method.Source:
int  active()
{
    int ret;
    TMSParameters   tMSParameters = TMSParameters::find();
    FormDataSource  fds = this;
    TMSAccessorialAssignment  tMSAccessorialAssignment;

    ret = next active();

    tMSAccessorialAssignment = fds.formRun().dataSource(formDataSourceStr(TMSAccessorialAssignment, TMSAccessorialAssignment)).cursor();

    fds.object(fieldNum(TMSAccessorialAssignment, KPMGCommon_NegativeFuelOilPercentage)).enabled(false);
    if (tMSParameters.KPMGCommon_CarrierAccessorialNegativeId == tMSAccessorialAssignment.CarrierAccessorialId)
        fds.object(fieldNum(TMSAccessorialAssignment, KPMGCommon_NegativeFuelOilPercentage)).enabled(true);

    return ret;
}
